import { forwardRef, useEffect, useId, useRef, useContext } from 'react';
import { CheckboxGroupContext } from '../CheckboxGroup/CheckboxGroup';
import { useControllableState } from '../../hooks/useControllableState';

export interface O9CheckboxProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, 'onChange'> {
  label?: string | null;
  isChecked?: boolean;
  defaultChecked?: boolean;
  isIndeterminate?: boolean;
  isDisabled?: boolean;
  isReadOnly?: boolean;
  isRequired?: boolean;
  isInvalid?: boolean;
  isExcluded?: boolean;
  size?: 'sm' | 'lg';
  value?: string;
  name?: string;
  errorMsg?: string | null;
  isInlineError?: boolean;
  isLoading?: boolean;
  onChange?: (detail: { isChecked: boolean; value: string }) => void;
  onFocus?: React.FocusEventHandler<HTMLInputElement>;
  onBlur?: React.FocusEventHandler<HTMLInputElement>;
}

const O9Checkbox = forwardRef<HTMLDivElement, O9CheckboxProps>(
  function O9Checkbox(
    {
      label = null,
      isChecked: checkedProp,
      defaultChecked = false,
      isIndeterminate = false,
      isDisabled = false,
      isReadOnly = false,
      isRequired = false,
      isInvalid = false,
      isExcluded = false,
      size = 'lg',
      value = 'on',
      name,
      errorMsg = null,
      isInlineError = true,
      isLoading = false,
      onChange,
      onFocus,
      onBlur,
      className,
      ...rest
    },
    ref
  ) {
    const uid = useId();
    const inputId = `o9ds-checkbox-${uid}`;
    const errorId = `o9ds-checkbox-err-${uid}`;
    const inputRef = useRef<HTMLInputElement>(null);

    const [isChecked, setChecked] = useControllableState(checkedProp, defaultChecked);

    // Consume group context — group values are defaults; individual props win for disabled
    const group = useContext(CheckboxGroupContext);
    const resolvedSize = group ? group.size : size;
    const resolvedDisabled = isDisabled || (group ? group.isDisabled : false);
    const resolvedReadonly = isReadOnly || (group ? group.isReadOnly : false);
    const resolvedLoading = isLoading || (group ? group.isLoading : false);
    const resolvedName = name ?? group?.name;

    // Register/unregister with group for select-all tracking
    useEffect(() => {
      if (!group || value === 'on') return;
      group.registerCheckbox(value, isChecked);
      return () => {
        group.unregisterCheckbox(value);
      };
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [value, group?.registerCheckbox, group?.unregisterCheckbox]);

    // Keep group in sync when checked changes externally
    useEffect(() => {
      if (!group || value === 'on') return;
      group.registerCheckbox(value, isChecked);
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isChecked]);

    useEffect(() => {
      if (inputRef.current) {
        inputRef.current.indeterminate = isIndeterminate;
        if (isIndeterminate) {
          inputRef.current.setAttribute('data-indeterminate', 'true');
        } else {
          inputRef.current.removeAttribute('data-indeterminate');
        }
      }
    }, [isIndeterminate]);

    const classes = [
      'o9ds-checkbox',
      `o9ds-checkbox--${resolvedSize}`,
      resolvedLoading && 'loading',
      resolvedDisabled && 'is-disabled',
      resolvedReadonly && 'is-readonly',
      isInvalid && 'has-error',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    function handleChange() {
      if (resolvedDisabled || resolvedLoading || resolvedReadonly) return;
      const nextChecked = isIndeterminate ? true : !isChecked;
      setChecked(nextChecked);
      onChange?.({ isChecked: nextChecked, value });
      group?.onChildChange(value, nextChecked);
    }

    const showAlert = isInvalid && isInlineError;
    const errorMessage = errorMsg || 'Error';

    return (
      <div
        ref={ref}
        className={classes}
        aria-busy={resolvedLoading || undefined}
        data-excluded={isExcluded || undefined}
        data-indeterminate={isIndeterminate || undefined}
        {...rest}
      >
        <label className="o9ds-checkbox__field">
          <input
            ref={inputRef}
            id={inputId}
            className="o9ds-checkbox__input"
            type="checkbox"
            name={resolvedName}
            value={value}
            checked={isChecked}
            disabled={resolvedDisabled}
            required={isRequired}
            aria-invalid={isInvalid || undefined}
            aria-required={isRequired || undefined}
            aria-describedby={showAlert ? errorId : undefined}
            onChange={handleChange}
            onFocus={onFocus}
            onBlur={onBlur}
          />
          {label && <span className="o9ds-checkbox__lbl">{label}</span>}
        </label>
        {showAlert && (
          <div className="o9ds-inline-alert o9ds-inline-alert--error" id={errorId} role="alert">
            <span className="o9ds-inline-alert__ico" aria-hidden="true" />
            <span className="o9ds-inline-alert__msg">{errorMessage}</span>
          </div>
        )}
      </div>
    );
  }
);

export default O9Checkbox;
